#include<bits/stdc++.h>
using namespace std;
long long n,a[15],lcm;
long long gcd(long long x, long long y){return ((y)?(gcd(y,x%y)):(x));}
int main(void){
	cin>>n;for(long long i=1;i<=n;i++)cin>>a[i];lcm=a[1];
	for(long long i=1;i<=n;i++)lcm=(lcm*a[i]/gcd(lcm,a[i]));
	cout<<lcm;
	return false;
}
